export type QuestionPurpose = 'characterize' | 'rule_in' | 'rule_out' | 'risk' | 'complication' | 'severity';

export interface SocratesQuestion {
  id: string;
  field: string;
  label: string;
  type: 'boolean' | 'select' | 'multi_select' | 'number' | 'text';
  options?: string[];
  condition?: string;
  clinicalGuide?: string;
  weight: number;
  purpose?: QuestionPurpose;
  targetDiagnoses?: string[];
}

const COMPLICATION_FIELDS = new Set([
  'altered_consciousness', 'bleeding', 'cyanosis', 'seizure', 'syncope',
  'jaundice', 'neck_stiffness', 'hemoptysis', 'hemoptysis_volume',
  'focal_neurological_deficit', 'signs_dehydration',
]);

export function autoPurpose(field: string): QuestionPurpose {
  if (field.startsWith('risk_')) return 'risk';
  if (field.startsWith('associated_')) return 'rule_in';
  if (COMPLICATION_FIELDS.has(field)) return 'complication';
  if (['severity', 'exercise_tolerance', 'sleep_quality', 'functional_impact'].includes(field)) return 'severity';
  return 'characterize';
}

