export function getQuestionsForSymptom(symptomId: string): SocratesQuestion[] {
  return (QUESTION_MAP[symptomId] || []).map(q => ({
    ...q,
    purpose: q.purpose || autoPurpose(q.field),
    targetDiagnoses: q.targetDiagnoses || [],
  }));
}

export interface SocratesStoredAnswer {
  questionId: string;
  answer: string | boolean | string[];
}

export function getFilteredQuestions(
  symptomId: string,
  answeredOrIds: string[] | SocratesStoredAnswer[]
): SocratesQuestion[] {
  const all = getQuestionsForSymptom(symptomId);
  const answeredIds: string[] = answeredOrIds.map(a =>
    typeof a === 'string' ? a : a.questionId
  );
  const answerMap = new Map<string, string | boolean | string[]>();
  for (const a of answeredOrIds) {
    if (typeof a !== 'string') {
      answerMap.set(a.questionId, a.answer);
    }
  }

  return all.filter(q => {
    if (answeredIds.includes(q.id)) return false;
    if (!q.condition) return true;

    if (q.condition.endsWith('!=')) {
      const condField = q.condition.slice(0, -2);
      const parentAnswer = answerMap.get(condField) ?? answerMap.get(`${symptomId}_${condField}`);
      if (parentAnswer === undefined) return false;
      const answerStr = String(parentAnswer);
      return answerStr.length > 0 && answerStr !== '' && answerStr !== 'Select...';
    }

    const eqIdx = q.condition.indexOf('=');
    const condField = q.condition.slice(0, eqIdx);
    const expectedValue = q.condition.slice(eqIdx + 1);
    const parentAnswer = answerMap.get(condField) ?? answerMap.get(`${symptomId}_${condField}`);
    if (parentAnswer === undefined) return false;
    const answerStr = String(parentAnswer).toLowerCase();
    return answerStr === expectedValue.toLowerCase();
  });
}
